What does this program print?

```cpp
#include <iostream>
class C {
    int v{};
public:
    C(int n) : v{ n } {}
    int get() const { return v; }
    C& operator++() { ++v; return *this; }
    C operator++(int) { C old{*this}; ++(*this); return old; }
};
int main() {
    C a{ 3 };
    std::cout << (a++).get() << ' ' << a.get() << '\n';
}
```

