This program should print `5 6` but instead causes undefined behavior. What is the bug?

```cpp
#include <iostream>
class C {
    int v{};
public:
    C(int n) : v{ n } {}
    int get() const { return v; }
    C& operator++(int) {   // postfix
        C old{ *this };
        ++v;
        return old;        // returns reference to local
    }
};
int main() {
    C a{ 5 };
    C b = a++;
    std::cout << b.get() << ' ' << a.get() << '\n';
}
